# Adoption funnel calculator: classify users into funnel stages from session logs

from datetime import date, timedelta
from collections import defaultdict
from dataclasses import dataclass, field

@dataclass
class Session:
    user_id: str
    date: date
    duration_minutes: float
    interactions: int   # prompts sent

def classify_user(user_id: str, sessions: list[Session]) -> str:
    """Returns the user's current highest funnel stage."""
    user_sessions = [s for s in sessions if s.user_id == user_id]
    valid = [s for s in user_sessions if s.duration_minutes >= 3 and s.interactions >= 1]

    if not valid:
        return "aware"  # access granted but no qualifying session

    # Trial: at least 1 valid session
    if len(valid) < 1:
        return "aware"

    # Activated: 5+ valid sessions in any 30-day window across 2+ weeks
    def check_activation():
        for anchor in valid:
            window = [s for s in valid
                      if anchor.date <= s.date <= anchor.date + timedelta(days=30)]
            if len(window) >= 5:
                weeks = {s.date.isocalendar()[1] for s in window}
                if len(weeks) >= 2:
                    return True
        return False

    if not check_activation():
        return "trial"

    # Regular: 3+ sessions/week in each of the last 4 consecutive weeks
    today = max(s.date for s in valid)
    weekly_counts = defaultdict(int)
    for s in valid:
        iso_week = s.date.isocalendar()[:2]
        weekly_counts[iso_week] += 1

    recent_weeks = sorted(weekly_counts.keys())[-4:]
    if len(recent_weeks) < 4:
        return "activated"
    if all(weekly_counts[w] >= 3 for w in recent_weeks):
        return "regular"

    return "activated"

def funnel_report(sessions: list[Session], user_ids: list[str]) -> dict:
    stages = defaultdict(int)
    for uid in user_ids:
        stage = classify_user(uid, sessions)
        stages[stage] += 1
    total = len(user_ids)
    return {
        "total_users": total,
        "stage_counts": dict(stages),
        "stage_pcts": {k: round(v/total*100,1) for k,v in stages.items()},
    }
